// ==================== Kafka Configuration ====================
@Configuration
class KafkaProducerConfig {

    @Value("${kafka.bootstrap.servers:localhost:9092}")
    private String bootstrapServers;

    @Value("${kafka.producer.acks:all}")
    private String acks;

    @Value("${kafka.producer.retries:3}")
    private int retries;

    @Value("${kafka.producer.linger.ms:1}")
    private int lingerMs;

    @Bean
    public KafkaProducer<String, String> kafkaProducer() {
        Properties props = new Properties();
        props.put(ProducerConfig.BOOTSTRAP_SERVERS_CONFIG, bootstrapServers);
        props.put(ProducerConfig.KEY_SERIALIZER_CLASS_CONFIG, StringSerializer.class.getName());
        props.put(ProducerConfig.VALUE_SERIALIZER_CLASS_CONFIG, StringSerializer.class.getName());
        props.put(ProducerConfig.ACKS_CONFIG, acks);
        props.put(ProducerConfig.RETRIES_CONFIG, retries);
        props.put(ProducerConfig.LINGER_MS_CONFIG, lingerMs);
        props.put(ProducerConfig.ENABLE_IDEMPOTENCE_CONFIG, true);
        return new KafkaProducer<>(props);
    }
}

// ==================== Kafka Producer Service ====================
@Service
class EventProducerService {

    private final KafkaProducer<String, String> kafkaProducer;

    // Well-known header keys for the event tracking system
    private static final String HEADER_TRACKING_ID = "tracking-id";
    private static final String HEADER_USER_ID = "user-id";
    private static final String HEADER_TIMESTAMP = "event-timestamp";
    private static final String HEADER_SOURCE = "event-source";
    private static final String HEADER_CONTENT_TYPE = "content-type";

    public EventProducerService(KafkaProducer<String, String> kafkaProducer) {
        this.kafkaProducer = kafkaProducer;
    }

    /**
     * Sends a message to Kafka with custom headers from the API request.
     *
     * @param eventMessage   the event payload including topic, key, value, and body-level headers
     * @param httpHeaders    additional headers extracted from the HTTP request
     * @return EventResponse with metadata about the sent record
     */
    public EventResponse sendEvent(EventMessage eventMessage, Map<String, String> httpHeaders) throws Exception {
        String topic = eventMessage.getTopic();
        String key = eventMessage.getKey();
        String value = eventMessage.getValue();

        // Merge all headers: body headers + HTTP request headers
        Map<String, String> allHeaders = new HashMap<>();

        // Add HTTP request-level headers (from X-* or known headers)
        if (httpHeaders != null) {
            allHeaders.putAll(httpHeaders);
        }

        // Add body-level headers (these override HTTP headers if same key)
        if (eventMessage.getHeaders() != null) {
            allHeaders.putAll(eventMessage.getHeaders());
        }

        // Auto-generate tracking-id if not provided
        String trackingId = allHeaders.getOrDefault(HEADER_TRACKING_ID, UUID.randomUUID().toString());
        allHeaders.put(HEADER_TRACKING_ID, trackingId);

        // Auto-add event timestamp if not provided
        if (!allHeaders.containsKey(HEADER_TIMESTAMP)) {
            allHeaders.put(HEADER_TIMESTAMP, String.valueOf(System.currentTimeMillis()));
        }

        // Auto-add content type if not provided
        if (!allHeaders.containsKey(HEADER_CONTENT_TYPE)) {
            allHeaders.put(HEADER_CONTENT_TYPE, "application/json");
        }

        // Build ProducerRecord
        ProducerRecord<String, String> record = new ProducerRecord<>(topic, key, value);

        // Inject all headers into the Kafka record
        Headers kafkaHeaders = record.headers();
        for (Map.Entry<String, String> entry : allHeaders.entrySet()) {
            kafkaHeaders.add(new RecordHeader(
                    entry.getKey(),
                    entry.getValue().getBytes(StandardCharsets.UTF_8)
            ));
        }

        // Send synchronously and capture metadata
        Future<RecordMetadata> future = kafkaProducer.send(record);
        RecordMetadata metadata = future.get();

        EventResponse response = new EventResponse();
        response.setStatus("SUCCESS");
        response.setMessage("Event published to Kafka successfully");
        response.setTopic(metadata.topic());
        response.setPartition(metadata.partition());
        response.setOffset(metadata.offset());
        response.setTrackingId(trackingId);
        response.setInjectedHeaders(allHeaders);

        return response;
    }

    @PreDestroy
    public void close() {
        if (kafkaProducer != null) {
            kafkaProducer.flush();
            kafkaProducer.close();
        }
    }
}

