@RestController
@RequestMapping("/api/v1/events")
class EventController {

    private final EventProducerService eventProducerService;

    // HTTP headers we extract and forward to Kafka
    private static final String[] FORWARDED_HTTP_HEADERS = {
            "tracking-id", "user-id", "correlation-id", "session-id",
            "client-version", "device-type", "event-source"
    };

    public EventController(EventProducerService eventProducerService) {
        this.eventProducerService = eventProducerService;
    }

    /**
     * POST /api/v1/events/publish
     *
     * Accepts an event message with optional custom headers in the body,
     * and also extracts well-known headers from the HTTP request.
     *
     * Example HTTP Headers:
     *   tracking-id: abc-123
     *   user-id: user-456
     *   X-Custom-Meta: some-value
     *
     * Example Body:
     * {
     *   "topic": "events-topic",
     *   "key": "order-123",
     *   "value": "{\"event\":\"ORDER_PLACED\",\"amount\":99.99}",
     *   "headers": {
     *     "event-type": "ORDER_PLACED",
     *     "priority": "high",
     *     "custom-metadata": "some-custom-value"
     *   }
     * }
     */
    @PostMapping("/publish")
    public ResponseEntity<EventResponse> publishEvent(
            @RequestBody EventMessage eventMessage,
            @RequestHeader Map<String, String> requestHeaders) {

        try {
            // Validate required fields
            if (eventMessage.getTopic() == null || eventMessage.getTopic().isBlank()) {
                EventResponse errorResponse = new EventResponse();
                errorResponse.setStatus("ERROR");
                errorResponse.setMessage("Topic is required");
                return ResponseEntity.badRequest().body(errorResponse);
            }

            if (eventMessage.getValue() == null || eventMessage.getValue().isBlank()) {
                EventResponse errorResponse = new EventResponse();
                errorResponse.setStatus("ERROR");
                errorResponse.setMessage("Value (event payload) is required");
                return ResponseEntity.badRequest().body(errorResponse);
            }

            // Extract relevant HTTP headers to forward to Kafka
            Map<String, String> httpHeadersToForward = extractRelevantHeaders(requestHeaders);

            EventResponse response = eventProducerService.sendEvent(eventMessage, httpHeadersToForward);
            return ResponseEntity.ok(response);

        } catch (Exception e) {
            EventResponse errorResponse = new EventResponse();
            errorResponse.setStatus("ERROR");
            errorResponse.setMessage("Failed to publish event: " + e.getMessage());
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(errorResponse);
        }
    }

    /**
     * POST /api/v1/events/publish-batch
     *
     * Sends multiple events in one request. All events share the same HTTP-level headers.
     */
    @PostMapping("/publish-batch")
    public ResponseEntity<Map<String, Object>> publishBatchEvents(
            @RequestBody java.util.List<EventMessage> eventMessages,
            @RequestHeader Map<String, String> requestHeaders) {

        Map<String, String> httpHeadersToForward = extractRelevantHeaders(requestHeaders);
        java.util.List<EventResponse> results = new java.util.ArrayList<>();
        int successCount = 0;
        int failureCount = 0;

        for (EventMessage eventMessage : eventMessages) {
            try {
                if (eventMessage.getTopic() == null || eventMessage.getTopic().isBlank() ||
                        eventMessage.getValue() == null || eventMessage.getValue().isBlank()) {
                    EventResponse errorResponse = new EventResponse();
                    errorResponse.setStatus("SKIPPED");
                    errorResponse.setMessage("Missing required fields (topic or value)");
                    results.add(errorResponse);
                    failureCount++;
                    continue;
                }
                EventResponse response = eventProducerService.sendEvent(eventMessage, httpHeadersToForward);
                results.add(response);
                successCount++;
            } catch (Exception e) {
                EventResponse errorResponse = new EventResponse();
                errorResponse.setStatus("ERROR");
                errorResponse.setMessage("Failed: " + e.getMessage());
                results.add(errorResponse);
                failureCount++;
            }
        }

        Map<String, Object> batchResponse = new HashMap<>();
        batchResponse.put("totalEvents", eventMessages.size());
        batchResponse.put("successCount", successCount);
        batchResponse.put("failureCount", failureCount);
        batchResponse.put("results", results);

        HttpStatus status = failureCount == 0 ? HttpStatus.OK : HttpStatus.MULTI_STATUS;
        return ResponseEntity.status(status).body(batchResponse);
    }

    /**
     * Extracts well-known and custom (X-prefixed) headers from HTTP request.
     */
    private Map<String, String> extractRelevantHeaders(Map<String, String> requestHeaders) {
        Map<String, String> extracted = new HashMap<>();

        if (requestHeaders == null) {
            return extracted;
        }

        // Extract well-known forwarded headers
        for (String headerKey : FORWARDED_HTTP_HEADERS) {
            String lowerKey = headerKey.toLowerCase();
            if (requestHeaders.containsKey(lowerKey)) {
                extracted.put(headerKey, requestHeaders.get(lowerKey));
            }
        }

        // Extract any custom headers prefixed with "x-" (common convention for custom HTTP headers)
        for (Map.Entry<String, String> entry : requestHeaders.entrySet()) {
            String key = entry.getKey().toLowerCase();
            if (key.startsWith("x-custom-") || key.startsWith("x-meta-")) {
                // Remove the "x-" prefix for cleaner Kafka headers, or keep as-is
                extracted.put(key, entry.getValue());
            }
        }

        return extracted;
    }
}